    if params.get("in_stock") not in (None, ""):
        in_stock = str(params["in_stock"]).lower() in ("1", "true", "yes", "y")
        if in_stock:
            where_clauses.append("stock > 0")
        else:
            where_clauses.append("stock = 0")

    if params.get("created_after") not in (None, ""):
        where_clauses.append("created_at >= %s")
        values.append(params["created_after"])

    if params.get("created_before") not in (None, ""):
        where_clauses.append("created_at <= %s")
        values.append(params["created_before"])

    if where_clauses:
        sql += " WHERE " + " AND ".join(where_clauses)

    sort_by = params.get("sort_by", "created_at")
    sort_order = str(params.get("sort_order", "desc")).lower()
    allowed_sort_fields = {"id", "name", "category", "price", "stock", "created_at", "updated_at"}
    if sort_by not in allowed_sort_fields:
        sort_by = "created_at"
    if sort_order not in ("asc", "desc"):
        sort_order = "desc"

    sql += f" ORDER BY {sort_by} {sort_order}"

    limit = params.get("limit")
